def parse_yaml_value(value: str):
    """Parse a YAML value string into Python type."""
    if not value:
        return None

    # Handle null values
    if value.lower() in ('null', '~'):
        return None

    # Handle booleans
    if value.lower() == 'true':
        return True
    if value.lower() == 'false':
        return False

    # Handle integers
    if re.match(r'^-?\d+$', value):
        return int(value)
